    agent_id: str = "temporal-agent-reclassifier"
    name: str = "temporal-agent-reclassifier"
    description: str = "MUST BE USED to provide standardized temporal reclassification of sub-agents to primary agents. Manages authority elevation, role transitions, delegation privileges, and hierarchical orchestration with comprehensive documentation and metrics tracking for exponential functionality scaling."
    type: str = "TASK"
